function parseTelegramMessage(input) {
  // Channel mapping to binary flags
  const channelFlags = {
    'x': 1,
    'threads': 2,
    'linkedin': 4,
    'all': 7
  };

  let flag = 0;
  let cleanedMessage = input;

  // Extract all @mentions
  const mentionRegex = /@(\w+)/g;
  const mentions = [...input.matchAll(mentionRegex)];

  // Process each mention
  for (const match of mentions) {
    const channel = match[1].toLowerCase();

    if (channelFlags.hasOwnProperty(channel)) {
      flag |= channelFlags[channel]; // Bitwise OR to combine flags
      // Remove the @mention from message
      cleanedMessage = cleanedMessage.replace(match[0], '');
    } else {
      // Invalid channel detected - return error flag
      return [-1, `Invalid channel: @${channel}`];
    }
  }

  // Remove all hashtags
  cleanedMessage = cleanedMessage.replace(/#\w+/g, '');

  // Clean up extra whitespace
  cleanedMessage = cleanedMessage.trim().replace(/\s+/g, ' ');

  return [flag, cleanedMessage];
}

const message = $input.first().json.channel_post.text

const [flag, parsedMessage] = parseTelegramMessage(message)

return [{"flag": flag, "parsedMessage": parsedMessage}];
